#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll a, b, c;    cin >> a >> b >> c;    if((2*b-a)%c==0 && (2*b-a)/c>0){        cout<<"YES\n";    }    else if((2*b-c)%a==0 && (2*b-c)/a>0){        cout<<"YES\n";    }    else if((a+c)/2*b>0 && ((a+c)/2)%b==0 && (c-a)%2==0){        cout<<"YES\n";    }    else{        cout<<"NO\n";    }       }        // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}